 860→    };
 861→
 862→    const fallbackWithReason = (reason) => {
 863→        debugPayload.ok = false;
 864→        debugPayload.fallback = true;
 865→        debugPayload.stage = 'fallback';
 866→        debugPayload.reason = reason;
 867→        if (debugMode) {
