 876→        if (!journal) {
 877→            return fallbackWithReason('journal_not_found');
 878→        }
 879→
 880→        const shareMeta = buildShareMetaFromJournal(journal);
 881→        debugPayload.stage = 'candidate_extracted';
 882→        debugPayload.meta.imageCandidateSource = shareMeta.imageCandidateSource;
 883→        debugPayload.meta.imageCandidateRaw = shareMeta.imageCandidate;
 884→
 885→        const candidateEvaluation = evaluateShareImageCandidate(shareMeta.imageCandidate);
 886→        debugPayload.meta.imageCandidateResolved = candidateEvaluation.resolvedUrl;
 887→        if (!candidateEvaluation.ok || !candidateEvaluation.resolvedUrl) {
 888→            return fallbackWithReason(candidateEvaluation.reason);
 889→        }
 890→
 891→        const normalizedFallbackUrl = new URL(DEFAULT_OG_IMAGE_URL).toString();
 892→        if (candidateEvaluation.resolvedUrl === normalizedFallbackUrl) {
 893→            return fallbackWithReason('candidate_is_default_fallback');
 894→        }
 895→
 896→        debugPayload.stage = 'fetching_upstream';
 897→        const remoteImage = await fetchRemoteImageBuffer(candidateEvaluation.resolvedUrl);
 898→        debugPayload.stage = 'upstream_loaded';
 899→        debugPayload.meta.upstreamFinalUrl = remoteImage.finalUrl;
 900→        debugPayload.meta.upstreamContentType = remoteImage.contentType;
 901→        debugPayload.meta.upstreamBytes = remoteImage.byteLength;
 902→
 903→        debugPayload.stage = 'converting_image';
 904→        const ogImageBuffer = await convertToOgJpeg(remoteImage.buffer);
 905→        debugPayload.stage = 'converted_image';
 906→        debugPayload.ok = true;
 907→        debugPayload.reason = 'ok';
 908→        debugPayload.meta.outputBytes = ogImageBuffer.length;
 909→
 910→        if (debugMode) {
 911→            return sendShareImageDebug(res, debugPayload);
 912→        }
 913→
 914→        setShareImageCached(`post:${journalId}`, ogImageBuffer);
 915→        res.set('Content-Type', 'image/jpeg');
 916→        res.set('Cache-Control', 'public, max-age=3600');
 917→        return res.send(ogImageBuffer);
 918→    } catch (err) {
 919→        debugPayload.stage = 'error';
 920→        debugPayload.reason = err?.message || 'unknown_error';
 921→        console.error('share image route error:', err?.message || err);
 922→        return fallbackWithReason(debugPayload.reason);
 923→    }
