282→                                    </div>
283→                                </div>
284→                                <div className="notification-settings">
285→                                    {settingsId === notification.id && (
286→                                        <AnimatePresence>
287→                                        <motion.div
288→                                        initial={{opacity: 0, scale: 0}}
289→                                        animate={{opacity: 1, scale: 1, transition:{type: 'spring', stiffness: 300, damping: 25, mass: 0.8}}}
290→                                        exit={{ opacity: 0, scale: 0,
291→                                            transition: {
292→                                            duration: 0.2,
293→                                            ease: "easeOut"
294→                                            }
295→                                        }}
296→                                        ref={modalRef}
297→                                        className="settings-container">
298→
299→                                            <div onClick={(e) => handleClickDeleteNotification(e, notification?.id, notification?.source)} className="delete-notification">
