 34→            }
 35→            return undefined;
 36→        },
 37→        enabled: !!opinionId,
 38→        refetchOnWindowFocus: false,
 39→        staleTime: 1000 * 60 * 5
 40→    });
 41→
 42→    const handleSubmitReplyOpinion = async (reply, receiver_id, sender_id, parent_id) => {
 43→        try {
 44→            const formadata = new FormData();
 45→            formadata.append('opinion', reply);
 46→            await addReplyOpinion(formadata, receiver_id, sender_id, parent_id, session?.access_token);
 47→            queryClient.invalidateQueries({ queryKey: ['getReplyOpinion', opinionId] });
 48→            queryClient.invalidateQueries({ queryKey: ['getOpinions'] });
 49→            queryClient.invalidateQueries({ queryKey: ['getViewOpinion'] });
 50→            setReplyOpinion('');
 51→            setShowReplyButtonId('');
 52→            setIsTypingId('');
